proof_block:
// The two run results (post1_self_, post2_self_) are constrained only by the
// ensures of `block_running_thread_and_set_trap_frame`, which is stated in
// terms of the relational view fns `get_container / get_proc / get_thread /
// get_endpoint`. Each ensures-forall triggers on a single `postN.get_X(...)`,
// so the two runs' forall instances never share triggers and z3 never lines
// them up. We bridge by:
//   (a) re-asserting each forall once per post-state with an explicit single
//       trigger so the same instantiation strategy is forced on both runs;
//   (b) for every key of every tracked perm map we run an
//       `assert forall ... by` with a single explicit trigger that chains
//       `is_init / addr` from `wf` to the per-key value equality coming from
//       the ensures, then lift to map extensionality;
//   (c) for `cpu_list@` we use Array's `=~=` (Seq extensionality) and for
//       `root_container` plain `==`.
// All inner steps are real `assert`s — nothing is taken on faith.

let target_ep = pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap();

// (a) Force both ensures-foralls into the z3 context under explicit triggers.
assert(forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr|
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));

assert(forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) ==> post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|c_ptr: ContainerPtr|
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) ==> post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));

assert(forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr ==>
        pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
assert(forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr ==>
        pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));

assert(forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_ep ==>
        pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
assert(forall|e_ptr: EndpointPtr|
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_ep ==>
        pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));

// (b1) container_perms@ : containers are completely unchanged.
assert(post1_self_.container_perms@.dom() =~= pre_self_.container_perms@.dom());
assert(post2_self_.container_perms@.dom() =~= pre_self_.container_perms@.dom());
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.container_perms@[c_ptr]]
    post1_self_.container_perms@.dom().contains(c_ptr) implies
    post1_self_.container_perms@[c_ptr] =~= post2_self_.container_perms@[c_ptr] by {
    assert(pre_self_.container_perms@.dom().contains(c_ptr));
    assert(post2_self_.container_perms@.dom().contains(c_ptr));
    assert(post1_self_.container_perms@[c_ptr].is_init());
    assert(post1_self_.container_perms@[c_ptr].addr() == c_ptr);
    assert(post2_self_.container_perms@[c_ptr].is_init());
    assert(post2_self_.container_perms@[c_ptr].addr() == c_ptr);
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post1_self_.container_perms@[c_ptr].value() =~= post2_self_.container_perms@[c_ptr].value());
};
assert(post1_self_.container_perms@ =~= post2_self_.container_perms@);

// (b2) process_perms@ : procs are completely unchanged.
assert(post1_self_.process_perms@.dom() =~= pre_self_.process_perms@.dom());
assert(post2_self_.process_perms@.dom() =~= pre_self_.process_perms@.dom());
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.process_perms@[p_ptr]]
    post1_self_.process_perms@.dom().contains(p_ptr) implies
    post1_self_.process_perms@[p_ptr] =~= post2_self_.process_perms@[p_ptr] by {
    assert(pre_self_.process_perms@.dom().contains(p_ptr));
    assert(post2_self_.process_perms@.dom().contains(p_ptr));
    assert(post1_self_.process_perms@[p_ptr].is_init());
    assert(post1_self_.process_perms@[p_ptr].addr() == p_ptr);
    assert(post2_self_.process_perms@[p_ptr].is_init());
    assert(post2_self_.process_perms@[p_ptr].addr() == p_ptr);
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post1_self_.process_perms@[p_ptr].value() =~= post2_self_.process_perms@[p_ptr].value());
};
assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);

// (b3) thread_perms@. For t_ptr != thread_ptr the thread is unchanged
// from pre, so post1 and post2 must both equal pre and thus each other.
// For t_ptr == thread_ptr the entire post-Thread is pinned via
// `pre_self_.get_thread(thread_ptr) =~= post1_self_.get_thread(thread_ptr)`
// (only the pinned-via-ensures fields differ, and the ensures pin those
// to the same values in both runs).
assert(post1_self_.thread_perms@.dom() =~= pre_self_.thread_perms@.dom());
assert(post2_self_.thread_perms@.dom() =~= pre_self_.thread_perms@.dom());
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.thread_perms@[t_ptr]]
    post1_self_.thread_perms@.dom().contains(t_ptr) implies
    post1_self_.thread_perms@[t_ptr] =~= post2_self_.thread_perms@[t_ptr] by {
    assert(pre_self_.thread_perms@.dom().contains(t_ptr));
    assert(post2_self_.thread_perms@.dom().contains(t_ptr));
    assert(post1_self_.thread_perms@[t_ptr].is_init());
    assert(post1_self_.thread_perms@[t_ptr].addr() == t_ptr);
    assert(post2_self_.thread_perms@[t_ptr].is_init());
    assert(post2_self_.thread_perms@[t_ptr].addr() == t_ptr);
    if t_ptr != thread_ptr {
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
        assert(post1_self_.thread_perms@[t_ptr].value()
            =~= post2_self_.thread_perms@[t_ptr].value());
    } else {
        assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
            =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
        assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors
            =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
        assert(post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
        assert(post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
        assert(post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
        assert(post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
        assert(post1_self_.thread_perms@[t_ptr].value()
            =~= post2_self_.thread_perms@[t_ptr].value());
    }
};
assert(post1_self_.thread_perms@ =~= post2_self_.thread_perms@);

// (b4) endpoint_perms@. For e_ptr != target_ep the endpoint is unchanged
// from pre. For e_ptr == target_ep: queue@, queue_state, owning_threads are
// pinned by the ensures and rf_counter is pinned via wf (= owning_threads@.len()).
assert(post1_self_.endpoint_perms@.dom() =~= pre_self_.endpoint_perms@.dom());
assert(post2_self_.endpoint_perms@.dom() =~= pre_self_.endpoint_perms@.dom());
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.endpoint_perms@[e_ptr]]
    post1_self_.endpoint_perms@.dom().contains(e_ptr) implies
    post1_self_.endpoint_perms@[e_ptr] =~= post2_self_.endpoint_perms@[e_ptr] by {
    assert(pre_self_.endpoint_perms@.dom().contains(e_ptr));
    assert(post2_self_.endpoint_perms@.dom().contains(e_ptr));
    assert(post1_self_.endpoint_perms@[e_ptr].is_init());
    assert(post1_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
    assert(post2_self_.endpoint_perms@[e_ptr].is_init());
    assert(post2_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
    if e_ptr != target_ep {
        assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
        assert(post1_self_.endpoint_perms@[e_ptr].value()
            =~= post2_self_.endpoint_perms@[e_ptr].value());
    } else {
        assert(post1_self_.get_endpoint(target_ep).queue@
            == pre_self_.get_endpoint(target_ep).queue@.push(thread_ptr));
        assert(post2_self_.get_endpoint(target_ep).queue@
            == pre_self_.get_endpoint(target_ep).queue@.push(thread_ptr));
        assert(post1_self_.get_endpoint(target_ep).queue_state
            == pre_self_.get_endpoint(target_ep).queue_state);
        assert(post2_self_.get_endpoint(target_ep).queue_state
            == pre_self_.get_endpoint(target_ep).queue_state);
        assert(post1_self_.get_endpoint(target_ep).owning_threads
            == pre_self_.get_endpoint(target_ep).owning_threads);
        assert(post2_self_.get_endpoint(target_ep).owning_threads
            == pre_self_.get_endpoint(target_ep).owning_threads);
        assert(post1_self_.get_endpoint(target_ep).rf_counter
            == post1_self_.get_endpoint(target_ep).owning_threads@.len());
        assert(post2_self_.get_endpoint(target_ep).rf_counter
            == post2_self_.get_endpoint(target_ep).owning_threads@.len());
        assert(post1_self_.endpoint_perms@[e_ptr].value()
            =~= post2_self_.endpoint_perms@[e_ptr].value());
    }
};
assert(post1_self_.endpoint_perms@ =~= post2_self_.endpoint_perms@);

// (c) cpu_list@ and root_container: neither the requires nor the ensures
// touch these, so they remain at their pre-state values in both runs.
assert(post1_self_.cpu_list@ =~= post2_self_.cpu_list@);
assert(post1_self_.root_container == post2_self_.root_container);

// (d) Both runs return `()`.
assert(r1 == r2);

// Close the det_..._equal disjunction.
assert(det_block_running_thread_and_set_trap_frame_equal(r1, r2, post1_self_, post2_self_));
